from collections import deque
from typing import List

def solve(edges: List[List[int]], online: List[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    in_degree = [0] * n
    for u, v, cost in edges:
        adj[u].append((v, cost))
        in_degree[v] += 1

    # Kahn's algorithm for topological sort
    q = deque()
    for i in range(n):
        if in_degree[i] == 0:
            q.append(i)
    topological_order = []
    while q:
        u = q.popleft()
        topological_order.append(u)
        for v, _ in adj[u]:
            in_degree[v] -= 1
            if in_degree[v] == 0:
                q.append(v)

    # Binary search for the maximum possible minimum edge cost
    max_edge = 0
    for u, v, cost in edges:
        if cost > max_edge:
            max_edge = cost

    low, high = 0, max_edge
    answer = -1

    while low <= high:
        mid = (low + high) // 2
        dist = [float('inf')] * n
        dist[0] = 0
        for u in topological_order:
            if not online[u]:
                continue
            for v, cost in adj[u]:
                if cost < mid:
                    continue
                if online[v]:
                    if dist[u] + cost < dist[v]:
                        dist[v] = dist[u] + cost
        if dist[-1] <= k:
            answer = mid
            low = mid + 1
        else:
            high = mid - 1

    return answer if answer != -1 else -1
