import heapq

def solve(edges: list[list[int]], online: list[bool], k: int) -> int:
    n = len(online)
    adj = [[] for _ in range(n)]
    for u, v, cost in edges:
        adj[u].append((v, cost))

    best_min = [-float('inf')] * n
    best_min[0] = float('inf')

    heap = []
    heapq.heappush(heap, (-float('inf'), 0, 0))

    while heap:
        current_neg_min, total_cost, u = heapq.heappop(heap)
        current_min = -current_neg_min

        if u == n - 1:
            return current_min

        if current_min < best_min[u]:
            continue

        for v, cost in adj[u]:
            if not online[v]:
                continue
            new_min = min(current_min, cost)
            new_total = total_cost + cost
            if new_total > k:
                continue
            if new_min > best_min[v]:
                best_min[v] = new_min
                heapq.heappush(heap, (-new_min, new_total, v))

    return -1
